// MARK: - Secure Enclave / Keychain Storage

enum WalletStoreError: Error {
    case secureEnclaveUnavailable
    case keyGenerationFailed
    case keyNotFound
    case keychain(OSStatus)
    case invalidData
}

final class WalletStore {
    static let shared = WalletStore()

    private let keyTagPrefix = "com.example.wallet.key."
    private let walletMetaKey = "com.example.wallet.meta"

    private init() {}

    func existingWallet() throws -> Wallet? {
        guard let data = try Keychain.getData(account: walletMetaKey) else { return nil }
        return try JSON.decoder.decode(Wallet.self, from: data)
    }

    func createWallet() throws -> CreateWalletResult {
        let id = UUID()
        let tag = keyTagPrefix + id.uuidString

        guard SecureEnclave.isAvailable else {
            throw WalletStoreError.secureEnclaveUnavailable
        }

        let access = SecAccessControlCreateWithFlags(nil,
                                                     kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
                                                     [.privateKeyUsage, .biometryAny],
                                                     nil)

        guard let accessControl = access else {
            throw WalletStoreError.keyGenerationFailed
        }

        let attributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256,
            kSecAttrTokenID as String: kSecAttrTokenIDSecureEnclave,
            kSecPrivateKeyAttrs as String: [
                kSecAttrIsPermanent as String: true,
                kSecAttrApplicationTag as String: tag.data(using: .utf8)!,
                kSecAttrAccessControl as String: accessControl
            ]
        ]

        var error: Unmanaged<CFError>?
        guard let privateKey = SecKeyCreateRandomKey(attributes as CFDictionary, &error) else {
            throw error?.takeRetainedValue() ?? WalletStoreError.keyGenerationFailed
        }

        guard let publicKey = SecKeyCopyPublicKey(privateKey) else {
            throw WalletStoreError.keyGenerationFailed
        }

        var pubErr: Unmanaged<CFError>?
        guard let pubData = SecKeyCopyExternalRepresentation(publicKey, &pubErr) as Data? else {
            throw pubErr?.takeRetainedValue() ?? WalletStoreError.keyGenerationFailed
        }

        let wallet = Wallet(id: id, createdAt: Date(), publicKeyX963Base64: pubData.base64EncodedString())

        let meta = try JSON.encoder.encode(wallet)
        try Keychain.setData(meta, account: walletMetaKey, accessible: kSecAttrAccessibleWhenUnlockedThisDeviceOnly)

        return CreateWalletResult(wallet: wallet)
    }

    func deleteWallet() throws {
        if let wallet = try existingWallet() {
            let tag = keyTagPrefix + wallet.id.uuidString
            try deletePrivateKey(tag: tag)
        }
        try Keychain.delete(account: walletMetaKey)
    }

    func privateKeyForCurrentWallet() throws -> SecKey {
        guard let wallet = try existingWallet() else { throw WalletStoreError.keyNotFound }
        let tag = keyTagPrefix + wallet.id.uuidString
        return try loadPrivateKey(tag: tag)
    }

    private func loadPrivateKey(tag: String) throws -> SecKey {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrApplicationTag as String: tag.data(using: .utf8)!,
            kSecReturnRef as String: true
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess, let key = item as! SecKey? else {
            throw WalletStoreError.keychain(status)
        }
        return key
    }

    private func deletePrivateKey(tag: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: tag.data(using: .utf8)!
        ]
        let status = SecItemDelete(query as CFDictionary)
        if status != errSecSuccess && status != errSecItemNotFound {
            throw WalletStoreError.keychain(status)
        }
    }
}

// MARK: - Keychain Wrapper

enum Keychain {
    static func setData(_ data: Data,
                        account: String,
                        accessible: CFString) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: accessible
        ]
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else { throw WalletStoreError.keychain(status) }
    }

    static func getData(account: String) throws -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        if status == errSecItemNotFound { return nil }
        guard status == errSecSuccess else { throw WalletStoreError.keychain(status) }
        return item as? Data
    }

    static func delete(account: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account
        ]
        let status = SecItemDelete(query as CFDictionary)
        if status != errSecSuccess && status != errSecItemNotFound {
            throw WalletStoreError.keychain(status)
        }
    }
}

// MARK: - Signing

enum SignerError: Error {
    case invalidPrivateKey
    case signFailed
}

final class TransactionSigner {
    static func sha256(_ data: Data) -> Data {
        Data(SHA256.hash(data: data))
    }

    static func sign(message: Data, with privateKey: SecKey) throws -> (der: Data, raw64: Data, hash: Data) {
        let hash = sha256(message)

        let algorithm = SecKeyAlgorithm.ecdsaSignatureMessageX962SHA256
        guard SecKeyIsAlgorithmSupported(privateKey, .sign, algorithm) else {
            throw SignerError.invalidPrivateKey
        }

        var error: Unmanaged<CFError>?
        guard let sigDER = SecKeyCreateSignature(privateKey, algorithm, message as CFData, &error) as Data? else {
            throw error?.takeRetainedValue() ?? SignerError.signFailed
        }

        let raw64 = try ECDSASignature.derToRaw64(sigDER)
        return (sigDER, raw64, hash)
    }
}

enum ECDSASignatureError: Error {
    case invalidDER
    case invalidInteger
    case invalidLength
}

enum ECDSASignature {
    static func derToRaw64(_ der: Data) throws -> Data {
        var i = 0
        func readByte() throws -> UInt8 {
            guard i < der.count else { throw ECDSASignatureError.invalidDER }
            let b = der[i]
            i += 1
            return b
        }
        func readLen() throws -> Int {
            let b = try readByte()
            if b & 0x80 == 0 { return Int(b) }
            let n = Int(b & 0x7f)
            guard n > 0 && n <= 2 else { throw ECDSASignatureError.invalidLength }
            var len = 0
            for _ in 0..<n {
                len = (len << 8) | Int(try readByte())
            }
            return len
        }
        func readInt() throws -> Data {
            let tag = try readByte()
            guard tag == 0x02 else { throw ECDSASignatureError.invalidDER }
            let len = try readLen()
            guard len > 0, i + len <= der.count else { throw ECDSASignatureError.invalidDER }
            var v = der.subdata(in: i..<(i+len))
            i += len
            while v.count > 0 && v.first == 0x00 && v.count > 32 {
                v.removeFirst()
            }
            if v.count > 32 { throw ECDSASignatureError.invalidInteger }
            if v.count < 32 {
                v = Data(repeating: 0, count: 32 - v.count) + v
            }
            return v
        }

        let seq = try readByte()
        guard seq == 0x30 else { throw ECDSASignatureError.invalidDER }
        _ = try readLen()
        let r = try readInt()
        let s = try readInt()
        return r + s
    }
}

// MARK: - Blockchain Communication (Generic JSON-RPC)

enum RPCError: Error {
    case invalidURL
    case network(Error)
    case badResponse
    case rpc(String)
    case decode
}

struct RPCRequest: Encodable {
    let jsonrpc: String = "2.0"
    let id: Int = Int.random(in: 1...Int.max)
    let method: String
    let params: [EncodableValue]
}

struct RPCResponse<Result: Decodable>: Decodable {
    struct RPCErrorObj: Decodable {
        let code: Int
        let message: String
    }
    let jsonrpc: String
    let id: Int?
    let result: Result?
    let error: RPCErrorObj?
}

enum EncodableValue: Encodable {
    case string(String)
    case int(Int)
    case bool(Bool)
    case double(Double)
    case object([String: EncodableValue])
    case array([EncodableValue])
    case null

    func encode(to encoder: Encoder) throws {
        var c = encoder.singleValueContainer()
        switch self {
        case .string(let v): try c.encode(v)
        case .int(let v): try c.encode(v)
        case .bool(let v): try c.encode(v)
        case .double(let v): try c.encode(v)
        case .object(let v): try c.encode(v)
        case .array(let v): try c.encode(v)
        case .null: try c.encodeNil()
        }
    }
}

final class JSONRPCClient {
    let endpoint: URL
    let session: URLSession

    init(endpoint: URL, session: URLSession = .shared) {
        self.endpoint = endpoint
        self.session = session
    }

    func call<Result: Decodable>(_ method: String,
                                 _ params: [EncodableValue],
                                 result: Result.Type) async throws -> Result {
        let reqObj = RPCRequest(method: method, params: params)
        let body = try JSON.encoder.encode(reqObj)

        var request = URLRequest(url: endpoint)
        request.httpMethod = "POST"
        request.httpBody = body
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        do {
            let (data, response) = try await session.data(for: request)
            guard let http = response as? HTTPURLResponse, (200..<300).contains(http.statusCode) else {
                throw RPCError.badResponse
            }
            let decoded = try JSON.decoder.decode(RPCResponse<Result>.self, from: data)
            if let err = decoded.error {
                throw RPCError.rpc(err.message)
            }
            guard let res = decoded.result else { throw RPCError.decode }
            return res
        } catch let e as RPCError {
            throw e
        } catch {
            throw RPCError.network(error)
        }
    }
}

// MARK: - Example Ethereum JSON-RPC (broadcast raw transaction)

final class EthereumRPC {
    private let rpc: JSONRPCClient

    init(endpoint: URL) {
        self.rpc = JSONRPCClient(endpoint: endpoint)
    }

    func chainId() async throws -> String {
        try await rpc.call("eth_chainId", [], result: String.self)
    }

    func getTransactionCount(addressHex: String, block: String = "latest") async throws -> String {
        try await rpc.call("eth_getTransactionCount", [.string(addressHex), .string(block)], result: String.self)
    }

    func sendRawTransaction(_ rawTxHex: String) async throws -> String {
        try await rpc.call("eth_sendRawTransaction", [.string(rawTxHex)], result: String.self)
    }
}

