    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Wallet MVP"
        view.backgroundColor = .systemBackground
        setupUI()
        refresh()
    }

    private func setupUI() {
        scroll.translatesAutoresizingMaskIntoConstraints = false
        stack.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(scroll)
        scroll.addSubview(stack)

        NSLayoutConstraint.activate([
            scroll.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor),
            scroll.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor),
            scroll.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scroll.bottomAnchor.constraint(equalTo: view.bottomAnchor),

            stack.leadingAnchor.constraint(equalTo: scroll.contentLayoutGuide.leadingAnchor, constant: 16),
            stack.trailingAnchor.constraint(equalTo: scroll.contentLayoutGuide.trailingAnchor, constant: -16),
            stack.topAnchor.constraint(equalTo: scroll.contentLayoutGuide.topAnchor, constant: 16),
            stack.bottomAnchor.constraint(equalTo: scroll.contentLayoutGuide.bottomAnchor, constant: -16),
            stack.widthAnchor.constraint(equalTo: scroll.frameLayoutGuide.widthAnchor, constant: -32)
        ])

        stack.axis = .vertical
        stack.spacing = 12

        statusLabel.numberOfLines = 0
        walletIdLabel.numberOfLines = 0
        pubKeyLabel.numberOfLines = 0
        pubKeyLabel.font = UIFont.monospacedSystemFont(ofSize: 12, weight: .regular)

        endpointField.borderStyle = .roundedRect
        endpointField.autocorrectionType = .no
        endpointField.autocapitalizationType = .none
        endpointField.placeholder = "Ethereum JSON-RPC endpoint (https://...)"
        endpointField.text = "https://cloudflare-eth.com"

        messageField.font = UIFont.monospacedSystemFont(ofSize: 13, weight: .regular)
        messageField.layer.borderWidth = 1
        messageField.layer.borderColor = UIColor.separator.cgColor
        messageField.layer.cornerRadius = 8
        messageField.text = #"{"to":"0x...","value":"0x0","data":"0x"}"#
        messageField.heightAnchor.constraint(equalToConstant: 120).isActive = true

        signatureField.font = UIFont.monospacedSystemFont(ofSize: 12, weight: .regular)
        signatureField.layer.borderWidth = 1
        signatureField.layer.borderColor = UIColor.separator.cgColor
        signatureField.layer.cornerRadius = 8
        signatureField.isEditable = false
        signatureField.heightAnchor.constraint(equalToConstant: 120).isActive = true

        hashField.font = UIFont.monospacedSystemFont(ofSize: 12, weight: .regular)
        hashField.layer.borderWidth = 1
        hashField.layer.borderColor = UIColor.separator.cgColor
        hashField.layer.cornerRadius = 8
        hashField.isEditable = false
        hashField.heightAnchor.constraint(equalToConstant: 70).isActive = true

        createButton.setTitle("Create Wallet (Secure Enclave)", for: .normal)
        deleteButton.setTitle("Delete Wallet", for: .normal)
        signButton.setTitle("Sign Message (SHA-256 + ECDSA P-256)", for: .normal)
        rpcPingButton.setTitle("RPC: Get Chain ID", for: .normal)

        createButton.addTarget(self, action: #selector(createWalletTapped), for: .touchUpInside)
        deleteButton.addTarget(self, action: #selector(deleteWalletTapped), for: .touchUpInside)
        signButton.addTarget(self, action: #selector(signTapped), for: .touchUpInside)
        rpcPingButton.addTarget(self, action: #selector(chainIdTapped), for: .touchUpInside)

        stack.addArrangedSubview(makeSection(title: "Status", views: [statusLabel]))
        stack.addArrangedSubview(makeSection(title: "Wallet", views: [walletIdLabel, pubKeyLabel, createButton, deleteButton]))
        stack.addArrangedSubview(makeSection(title: "Blockchain RPC", views: [endpointField, rpcPingButton]))
        stack.addArrangedSubview(makeSection(title: "Message to Sign", views: [messageField, signButton]))
        stack.addArrangedSubview(makeSection(title: "Hash (hex)", views: [hashField]))
        stack.addArrangedSubview(makeSection(title: "Signature (Base64)", views: [signatureField]))

        let pad = UITapGestureRecognizer(target: self, action: #selector(endEditingTap))
        pad.cancelsTouchesInView = false
        view.addGestureRecognizer(pad)
    }

    private func makeSection(title: String, views: [UIView]) -> UIView {
        let container = UIStackView()
        container.axis = .vertical
        container.spacing = 8

        let label = UILabel()
        label.text = title
        label.font = .systemFont(ofSize: 15, weight: .semibold)

        container.addArrangedSubview(label)
        for v in views { container.addArrangedSubview(v) }
        return container
    }

    @objc private func endEditingTap() {
        view.endEditing(true)
    }

    private func refresh() {
        do {
            if let wallet = try WalletStore.shared.existingWallet() {
                statusLabel.text = "Wallet ready"
                walletIdLabel.text = "ID: \(wallet.id.uuidString)\nCreated: \(wallet.createdAt)"
                pubKeyLabel.text = "Public Key (X9.63, Base64):\n\(wallet.publicKeyX963Base64)"
                deleteButton.isEnabled = true
                signButton.isEnabled = true
                createButton.isEnabled = false
            } else {
                statusLabel.text = "No wallet found. Create one."
                walletIdLabel.text = "ID: —"
                pubKeyLabel.text = "Public Key: —"
                deleteButton.isEnabled = false
                signButton.isEnabled = false
                createButton.isEnabled = true
            }
        } catch {
            statusLabel.text = "Error: \(error)"
            createButton.isEnabled = true
            deleteButton.isEnabled = false
            signButton.isEnabled = false
        }
    }

    @objc private func createWalletTapped() {
        Task { @MainActor in
            do {
                _ = try WalletStore.shared.createWallet()
                statusLabel.text = "Created wallet"
                refresh()
            } catch {
                statusLabel.text = "Create failed: \(error)"
            }
        }
    }

    @objc private func deleteWalletTapped() {
        Task { @MainActor in
            do {
                try WalletStore.shared.deleteWallet()
                statusLabel.text = "Deleted wallet"
                signatureField.text = ""
                hashField.text = ""
                refresh()
            } catch {
                statusLabel.text = "Delete failed: \(error)"
            }
        }
    }

    @objc private func signTapped() {
        Task { @MainActor in
            do {
                let message = Data(messageField.text.utf8)
                let priv = try WalletStore.shared.privateKeyForCurrentWallet()
                let (der, raw64, hash) = try TransactionSigner.sign(message: message, with: priv)

                let wallet = try WalletStore.shared.existingWallet()!
                let res = SignResult(
                    signatureDERBase64: der.base64EncodedString(),
                    signatureRaw64Base64: raw64.base64EncodedString(),
                    messageHashHex: Hex.encode(hash),
                    publicKeyX963Base64: wallet.publicKeyX963Base64
                )

                hashField.text = res.messageHashHex
                signatureField.text = """
                DER(Base64):
                \(res.signatureDERBase64)

                RAW64(Base64) [r||s]:
                \(res.signatureRaw64Base64)

                PublicKey X9.63(Base64):
                \(res.publicKeyX963Base64)
                """
                statusLabel.text = "Signed message"
            } catch {
                statusLabel.text = "Sign failed: \(error)"
            }
        }
    }

    @objc private func chainIdTapped() {
        Task { @MainActor in
            do {
                guard let s = endpointField.text, let url = URL(string: s) else {
                    statusLabel.text = "Invalid endpoint URL"
                    return
                }
                let eth = EthereumRPC(endpoint: url)
                let chainId = try await eth.chainId()
                statusLabel.text = "Chain ID: \(chainId)"
            } catch {
                statusLabel.text = "RPC failed: \(error)"
            }
        }
    }
}